  "about.hero.titleHighlight": { fr: "eau pure", ar: "ماء نقي", en: "pure water" },
  "about.hero.subtitle": { fr: "Filtre Maroc accompagne les familles et les professionnels avec des solutions de filtration fiables, abordables et adaptées à la qualité de l'eau au Maroc.", ar: "ترافق Filtre Maroc العائلات والمهنيين بحلول ترشيح موثوقة وبأسعار مناسبة وملائمة لجودة الماء في المغرب.", en: "Filtre Maroc supports families and professionals with reliable, affordable filtration solutions tailored to water quality in Morocco." },
  "about.stats.0.label": { fr: "Clients satisfaits", ar: "عميل راضٍ", en: "Satisfied customers" },
  "about.stats.1.label": { fr: "Villes desservies", ar: "مدينة مغطاة", en: "Cities served" },
