/** Translate a key for a locale, with {var} interpolation. */
export function translate(
  locale: Locale,
  key: string,
  vars?: Record<string, string | number>,
): string {
  const entry = DICT[key];
  let str = entry ? (entry[locale] ?? entry.fr) : key;
  if (vars) {
    for (const [k, v] of Object.entries(vars)) {
      str = str.replace(new RegExp(`\\{${k}\\}`, "g"), String(v));
    }
  }
  return str;
}

/** Translate a product badge label (data is stored in French). */
export function translateBadge(locale: Locale, label: string): string {
  return translate(locale, `badge.${label}`);
}
